static const int kI18nCount = (int)(sizeof(kI18n) / sizeof(kI18n[0]));

const char* TR(const char* en) {
  if (!en) return "";
  if (s_ui_lang == LANG_EN) return en;
  for (int i = 0; i < kI18nCount; ++i) {
    if (strcmp(en, kI18n[i].en) == 0) {
      const char* v = kI18n[i].tr[s_ui_lang];
      return v ? v : en;
    }
  }
  return en;   // not in the table -> English
}
